const chatInput = `Analiza este ticket y asigna los tags apropiados:

Ticket ID: ${$input.first().json.ticket.id}
Asunto: ${$input.first().json.ticket.subject}
Descripción: ${$input.first().json.ticket.description}

Tags disponibles (solo puedes elegir de estos):
${JSON.stringify($input.first().json.available_tags, null, 2)}

Devuelve el resultado en formato JSON con ticket_id y tag_ids (array de números).`;

return [
  {
    json: {
      chatInput: chatInput
    }
  }
];

const llmOutput = $input.first().json.output;
const available = $('Set Data Webhook').first().json.available_tags;
const availableIds = (available || []).map(t => Number(t.id));

const requested = (llmOutput.tag_ids || []).map(Number);
const valid = requested.filter(id => availableIds.includes(id));
const dropped = requested.filter(id => !availableIds.includes(id));

if (dropped.length > 0) {
  console.warn('LLM hallucinated tag_ids', { dropped, ticket_id: llmOutput.ticket_id });
}

return [{ json: {
  ticket_id: Number(llmOutput.ticket_id),
  tag_ids: valid,
  dropped: dropped,
}}];

const validated = $('Validar tag_ids').first().json;
const response = $input.first().json;

console.log('Tagging applied', {
  ticket_id: validated.ticket_id,
  requested: validated.tag_ids,
  hallucinated_dropped: validated.dropped,
  added: response.added ?? [],
  skipped_existing: response.skipped_existing ?? [],
  skipped_unknown: response.skipped_unknown ?? [],
});

return [{ json: response }];
